"use client";

import { type CheckboxProps, Checkbox as CheckboxRoot, type CheckboxVariant } from "./checkbox";
import { CheckboxGroup, type CheckboxGroupProps } from "./checkbox-group";
import { CheckboxItem, type CheckboxItemProps } from "./checkbox-item";

const Checkbox = Object.assign(CheckboxRoot, {
  Group: CheckboxGroup,
  Item: CheckboxItem,
});

export { Checkbox, type CheckboxProps, type CheckboxVariant };
export { CheckboxGroup, type CheckboxGroupProps };
export { CheckboxItem, type CheckboxItemProps };

"use client";

import {
  type AriaAttributes,
  type ComponentPropsWithRef,
  type KeyboardEvent as ReactKeyboardEvent,
  type MouseEvent as ReactMouseEvent,
  type ReactNode,
  type Ref,
  useId,
  useRef,
  useState,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useFormReset } from "@/hooks/use-form-reset";
import { mergeIds, resolveAriaInvalid } from "@/lib/aria";
import { composeRefs } from "@/lib/compose-refs";
import {
  type SelectableSize,
  type SelectableVariant,
  selectableContainerClass,
  selectableDescriptionVariants,
  selectableIndicators,
  selectableIndicatorVariants,
  selectableLabelVariants,
  selectableVariants,
} from "@/lib/selectable-variants";
import { cn } from "@/lib/utils";

type CheckboxState = "indeterminate" | "checked" | "unchecked";

function resolveCheckboxState(indeterminate: boolean, checked: boolean): CheckboxState {
  if (indeterminate) return "indeterminate";
  if (checked) return "checked";
  return "unchecked";
}

export type CheckboxSize = SelectableSize;

export type CheckboxVariant = SelectableVariant;

type CheckboxRootProps = Omit<
  ComponentPropsWithRef<"div">,
  | "children"
  | "role"
  | "aria-checked"
  | "aria-disabled"
  | "aria-required"
  | "aria-invalid"
  | "aria-label"
  | "aria-labelledby"
  | "aria-describedby"
  | "tabIndex"
  | "onChange"
  | "className"
  | "ref"
  | "data-value"
>;

export type CheckboxProps = CheckboxRootProps & {
  checked?: boolean | "indeterminate";
  defaultChecked?: boolean;
  onChange?: (checked: boolean) => void;
  label?: ReactNode;
  description?: ReactNode;
  disabled?: boolean;
  highlighted?: boolean;
  size?: CheckboxSize;
  variant?: CheckboxVariant;
  strikethrough?: boolean;
  value?: string;
  name?: string;
  required?: boolean;
  "aria-label"?: string;
  "aria-labelledby"?: string;
  "aria-describedby"?: string;
  "aria-invalid"?: AriaAttributes["aria-invalid"];
  className?: string;
  "data-value"?: string;
  ref?: Ref<HTMLDivElement>;
};

export function Checkbox({
  checked: controlledChecked,
  defaultChecked = false,
  onChange,
  onClick,
  onKeyDown,
  onMouseEnter,
  label,
  description,
  disabled = false,
  highlighted = false,
  size = "md",
  variant = "x",
  strikethrough = false,
  value = "on",
  name,
  required,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  "aria-describedby": ariaDescribedBy,
  "aria-invalid": ariaInvalid,
  className,
  "data-value": dataValue,
  ref,
  ...rootProps
}: CheckboxProps) {
  const generatedId = useId();
  const labelId = `${generatedId}-label`;
  const descriptionId = `${generatedId}-desc`;
  const isIndeterminate = controlledChecked === "indeterminate";
  const controlledBool = controlledChecked === undefined
    ? undefined
    : controlledChecked === true;

  const rootRef = useRef<HTMLDivElement>(null);
  const [isChecked, setIsChecked] = useControllableState<boolean>({
    value: controlledBool,
    defaultValue: defaultChecked,
    onChange,
  });
  const state = resolveCheckboxState(isIndeterminate, isChecked);
  const [nativeInvalid, setNativeInvalid] = useState(false);
  const resolvedAriaInvalid = resolveAriaInvalid(ariaInvalid, nativeInvalid && required && !isChecked);
  const resolvedAriaLabelledBy = ariaLabel
    ? undefined
    : mergeIds(ariaLabelledBy, label ? labelId : undefined);
  const resolvedAriaDescribedBy = mergeIds(
    ariaDescribedBy,
    description ? descriptionId : undefined,
  );

  useFormReset(rootRef, defaultChecked, setIsChecked, controlledBool === undefined);

  const toggle = () => {
    if (disabled) return;
    setNativeInvalid(false);
    setIsChecked(!isChecked);
  };

  const handleClick = (event: ReactMouseEvent<HTMLDivElement>) => {
    if (disabled) {
      event.preventDefault();
      return;
    }
    onClick?.(event);
    if (!event.defaultPrevented) toggle();
  };

  const handleKeyDown = (e: ReactKeyboardEvent<HTMLDivElement>) => {
    if (disabled) {
      e.preventDefault();
      return;
    }
    onKeyDown?.(e);
    if (e.defaultPrevented) return;
    if (e.key === " ") {
      e.preventDefault();
      toggle();
    }
  };

  const indicator = selectableIndicators[variant][state];

  return (
    <>
      {(name || required) && (
        // Validation/submission-only mirror: aria-hidden keeps it out of the
        // a11y tree, so naming/invalid/described-by live on the visible control.
        <input
          type="checkbox"
          name={name}
          value={value}
          checked={isChecked}
          required={required}
          disabled={disabled}
          className="sr-only"
          tabIndex={-1}
          readOnly
          aria-hidden={true}
          onInvalid={(event) => {
            event.preventDefault();
            setNativeInvalid(true);
            rootRef.current?.focus();
          }}
        />
      )}
      {/* biome-ignore lint/a11y/useSemanticElements: this is the custom-styled checkbox control; a hidden native <input type="checkbox"> (rendered separately) owns form submission, so the visible control uses role="checkbox". */}
      <div
        {...rootProps}
        ref={composeRefs(rootRef, ref)}
        role="checkbox"
        data-value={dataValue ?? value}
        data-highlighted={highlighted ? "true" : undefined}
        aria-checked={isIndeterminate ? "mixed" : isChecked}
        aria-disabled={disabled || undefined}
        aria-required={required || undefined}
        aria-invalid={resolvedAriaInvalid}
        aria-label={ariaLabel}
        aria-labelledby={resolvedAriaLabelledBy}
        aria-describedby={resolvedAriaDescribedBy}
        tabIndex={disabled ? -1 : 0}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        onMouseEnter={onMouseEnter}
        className={cn(
          selectableVariants({ highlighted, disabled }),
          selectableContainerClass,
          description && "items-start",
          className,
        )}
      >
        <span aria-hidden="true" className={selectableIndicatorVariants({ size, checked: isChecked, highlighted })}>
          {indicator}
        </span>
        {label && (
          <div className={cn("flex flex-col min-w-0", !description && "justify-center")}>
            <span id={labelId} className={cn(selectableLabelVariants({ size }), strikethrough && isChecked && "text-muted-foreground line-through")}>{label}</span>
            {description && (
              <span id={descriptionId} className={selectableDescriptionVariants({ highlighted })}>{description}</span>
            )}
          </div>
        )}
      </div>
    </>
  );
}

"use client";

import {
  type AriaAttributes,
  type ComponentPropsWithRef,
  type KeyboardEvent as ReactKeyboardEvent,
  type ReactNode,
  type Ref,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useFormReset } from "@/hooks/use-form-reset";
import { useNavigation } from "@/hooks/use-navigation";
import { isHTMLElementForContainer, resolveAriaInvalid } from "@/lib/aria";
import { composeRefs } from "@/lib/compose-refs";
import {
  getEnabledSelectableCollectionItems,
  resolveSelectableCollectionItem,
  useSelectableCollection,
} from "@/lib/selectable-collection";
import type { SelectableVariant } from "@/lib/selectable-variants";
import { cn } from "@/lib/utils";
import type { CheckboxSize } from "./checkbox";
import { CheckboxGroupContext } from "./checkbox-group-context";

type CheckboxGroupRootProps = Omit<
  ComponentPropsWithRef<"div">,
  | "children"
  | "role"
  | "onChange"
  | "onKeyDown"
  | "className"
  | "ref"
  | "aria-label"
  | "aria-labelledby"
  | "aria-disabled"
  | "aria-invalid"
>;

export type CheckboxGroupProps<T extends string = string> = CheckboxGroupRootProps & {
  value?: T[];
  defaultValue?: T[];
  onChange?: (value: T[]) => void;
  onHighlightChange?: (value: string | null) => void;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
  highlighted?: string | null;
  wrap?: boolean;
  keyboardNavigation?: boolean;
  onNavigationBoundaryReached?: (
    direction: "previous" | "next",
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
  disabled?: boolean;
  autoFocus?: boolean;
  size?: CheckboxSize;
  variant?: SelectableVariant;
  strikethrough?: boolean;
  name?: string;
  required?: boolean;
  className?: string;
  label?: string;
  "aria-label"?: string;
  "aria-labelledby"?: string;
  "aria-invalid"?: AriaAttributes["aria-invalid"];
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
};

export function CheckboxGroup<T extends string = string>(props: CheckboxGroupProps<T>) {
  const {
    value: controlledValue,
    defaultValue = [] as T[],
    onChange,
    onHighlightChange,
    onKeyDown,
    highlighted: controlledHighlighted,
    wrap = true,
    keyboardNavigation = true,
    onNavigationBoundaryReached,
    disabled = false,
    autoFocus = false,
    size = "md",
    variant = "x",
    strikethrough = false,
    name,
    required,
    className,
    label,
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
    "aria-invalid": ariaInvalid,
    children,
    ref,
    ...rootProps
  } = props;
  const containerRef = useRef<HTMLDivElement>(null);
  const hasAutoFocusedRef = useRef(false);
  const { items, registerItem, unregisterItem } = useSelectableCollection(containerRef);
  const [value, setValue] = useControllableState<T[]>({
    value: "value" in props ? controlledValue ?? [] : undefined,
    controlled: "value" in props,
    defaultValue,
    onChange,
  });
  const [nativeInvalid, setNativeInvalid] = useState(false);
  useFormReset(containerRef, defaultValue, setValue, !("value" in props));

  const enabledItemValues = new Set(
    getEnabledSelectableCollectionItems(items, disabled).map((item) => item.value),
  );
  const hasValidSelectedValue = value.some((itemValue) => enabledItemValues.has(itemValue));

  const [highlightedValue, setHighlightedValue] = useControllableState<string | null>({
    value: controlledHighlighted,
    controlled: "highlighted" in props,
    defaultValue: null,
    onChange: onHighlightChange,
  });

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "checkbox",
    wrap,
    enabled: keyboardNavigation && !disabled,
    onNavigationBoundaryReached,
    highlighted: highlightedValue,
    onHighlightChange: setHighlightedValue,
    onEnter: (itemValue) => toggle(itemValue),
    moveFocus: true,
    scopeToContainer: true,
    ownerSelector: '[data-diffgazer-selectable-owner="checkbox"]',
  });

  useEffect(() => {
    if (!autoFocus || !keyboardNavigation || disabled) {
      hasAutoFocusedRef.current = false;
      return;
    }
    if (hasAutoFocusedRef.current) return;

    const activeItems = getEnabledSelectableCollectionItems(items, disabled);
    const target = resolveSelectableCollectionItem(activeItems, highlightedValue, ...value);
    if (!target?.element) return;

    target.element.focus();
    setHighlightedValue(target.value);
    hasAutoFocusedRef.current = true;
  }, [autoFocus, keyboardNavigation, disabled, items, highlightedValue, value, setHighlightedValue]);

  const toggle = useCallback((itemValue: string) => {
    if (disabled) return;
    setNativeInvalid(false);
    setValue((cur) => {
      const nextValue = itemValue as T;
      const selected = cur.includes(nextValue);
      return selected
        ? cur.filter((v) => v !== itemValue)
        : [...cur, nextValue];
    });
  }, [disabled, setValue]);

  const handleKeyDown = (event: ReactKeyboardEvent) => {
    const eventTarget = isHTMLElementForContainer(event.target, containerRef.current)
      ? event.target
      : null;
    if (
      eventTarget
      && eventTarget.closest('[role="group"]') !== containerRef.current
    ) {
      return;
    }

    onKeyDown?.(event);
    if (!event.defaultPrevented && event.key !== " ") navKeyDown(event);
  };

  const contextValue = useMemo(() => ({
    value,
    toggle,
    registerItem,
    unregisterItem,
    disabled,
    size,
    variant,
    strikethrough,
    highlightedValue: highlightedValue ?? null,
    name,
  }), [value, toggle, registerItem, unregisterItem, disabled, size, variant, strikethrough, highlightedValue, name]);

  return (
    <CheckboxGroupContext value={contextValue}>
      {/* biome-ignore lint/a11y/useSemanticElements: role="group" labels the set of related checkboxes; <fieldset> would impose default form styling/structure and break the group layout. */}
      <div
        {...rootProps}
        ref={composeRefs(containerRef, ref)}
        role="group"
        data-diffgazer-selectable-owner="checkbox"
        aria-label={ariaLabel ?? label}
        aria-labelledby={ariaLabelledBy}
        aria-disabled={disabled || undefined}
        aria-invalid={resolveAriaInvalid(ariaInvalid, nativeInvalid && required && !hasValidSelectedValue)}
        className={cn("flex flex-col gap-2", className)}
        onKeyDown={handleKeyDown}
      >
        {required && (
          // Validation-only mirror: aria-hidden keeps it out of the a11y tree,
          // so naming and invalid state live on the visible role="group".
          <input
            type="checkbox"
            required
            checked={hasValidSelectedValue}
            disabled={disabled}
            tabIndex={-1}
            aria-hidden={true}
            readOnly
            className="sr-only"
            onInvalid={(event) => {
              event.preventDefault();
              setNativeInvalid(true);
              getEnabledSelectableCollectionItems(items, disabled)[0]?.element?.focus();
            }}
          />
        )}
        {children}
      </div>
    </CheckboxGroupContext>
  );
}

"use client";

import { type ReactNode, type Ref, useId, useLayoutEffect, useRef } from "react";
import { composeRefs } from "@/lib/compose-refs";
import { Checkbox, type CheckboxProps } from "./checkbox";
import { useCheckboxGroupContext } from "./checkbox-group-context";

export type CheckboxItemProps = Omit<
  CheckboxProps,
  | "checked"
  | "defaultChecked"
  | "onChange"
  | "highlighted"
  | "size"
  | "variant"
  | "strikethrough"
  | "name"
  | "value"
  | "data-value"
  | "required"
> & {
  value: string;
  label: ReactNode;
  description?: ReactNode;
  disabled?: boolean;
  ref?: Ref<HTMLDivElement>;
};

export function CheckboxItem({ value, label, description, disabled = false, ref, ...checkboxProps }: CheckboxItemProps) {
  const ctx = useCheckboxGroupContext();
  const itemId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const isDisabled = disabled || ctx.disabled;
  const { registerItem, unregisterItem } = ctx;

  useLayoutEffect(() => {
    registerItem(itemId, value, disabled, rootRef.current);
    return () => unregisterItem(itemId);
  }, [registerItem, unregisterItem, itemId, value, disabled]);

  return (
    <Checkbox
      {...checkboxProps}
      ref={composeRefs(rootRef, ref)}
      value={value}
      data-value={value}
      checked={ctx.value.includes(value)}
      onChange={() => ctx.toggle(value)}
      label={label}
      description={description}
      disabled={isDisabled}
      highlighted={ctx.highlightedValue === value}
      size={ctx.size}
      variant={ctx.variant}
      strikethrough={ctx.strikethrough}
      name={ctx.name}
    />
  );
}

"use client";

import { createContext, useContext } from "react";
import type { SelectableVariant } from "@/lib/selectable-variants";
import type { CheckboxSize } from "./checkbox";

export type CheckboxGroupContextValue = {
  value: string[];
  toggle: (itemValue: string) => void;
  registerItem: (itemId: string, itemValue: string, disabled: boolean, element: HTMLElement | null) => void;
  unregisterItem: (itemId: string) => void;
  disabled: boolean;
  size: CheckboxSize;
  variant: SelectableVariant;
  strikethrough: boolean;
  highlightedValue: string | null;
  name?: string;
};

export const CheckboxGroupContext = createContext<CheckboxGroupContextValue | undefined>(undefined);

export function useCheckboxGroupContext() {
  const context = useContext(CheckboxGroupContext);
  if (!context) throw new Error("CheckboxItem must be used within CheckboxGroup");
  return context;
}
